import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule, NgIf, NgFor, DatePipe } from '@angular/common';
import { AdminService } from '../../../core/services/admin.service';

@Component({
  selector: 'app-manage-users',
  standalone: true,
  imports: [CommonModule, NgIf, NgFor, DatePipe],
  templateUrl: './manage-users.component.html',
  styleUrls: ['./manage-users.component.css']
})
export class ManageUsersComponent implements OnInit {
  private adminService = inject(AdminService);
  private cdr = inject(ChangeDetectorRef);

  usersList: any[] = [];
  isLoading = false;

  ngOnInit(): void {
    this.isLoading = true;
    this.adminService.getAllUsers().subscribe({
      next: (data) => {
        this.usersList = data;
        this.isLoading = false;
        this.cdr.detectChanges();
      },
      error: () => this.isLoading = false
    });
  }

  onDeleteUser(userId: number): void {
    if (confirm("⚠️ Êtes-vous sûr de vouloir supprimer définitivement cet utilisateur de Tun-Job ?")) {
      this.adminService.deleteUser(userId).subscribe({
        next: () => {
          this.usersList = this.usersList.filter(u => u.id !== userId);
          this.cdr.detectChanges();
        }
      });
    }
  }
}
 
<div class="manage-container">
  <div class="card-header-flex">
    <div class="card-header-left">
      <h3><i class="bi bi-person-gear"></i> Gestion des Utilisateurs</h3>
      <p>Consultez la liste des membres inscrits et modérez les accès à la plateforme.</p>
    </div>
  </div>

  <div class="manage-card-premium">
    <div class="table-wrapper-premium">
      
      <div *ngIf="isLoading" class="loading-box">
        <i class="bi bi-arrow-clockwise spinning"></i> Chargement des comptes utilisateurs...
      </div>

      <table *ngIf="!isLoading" class="jobs-table-premium">
        <thead>
          <tr>
            <th class="th-left-padding">Nom / Rôle</th>
            <th>Adresse E-mail</th>
            <th>Statut du compte</th>
            <th class="th-center-align">Actions</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let user of usersList" class="table-row-premium">
            <td class="job-company-cell">
              <span class="clickable-job-title" style="font-size: 14px !important; font-weight: 700;">{{ user.name }}</span>
              <span class="company-sub-badge">
                <i class="bi" [ngClass]="user.role === 'recruiter' ? 'bi-building' : 'bi-person'"></i> 
                {{ user.role === 'recruiter' ? 'Recruteur' : 'Candidat' }}
              </span>
            </td>
            <td class="date-text-cell-premium">{{ user.email }}</td>
            <td>
              <span class="status-badge-fixed" [ngClass]="user.is_verified ? 'bg-emerald' : 'bg-amber'">
                <span class="dot-status"></span>
                <span class="badge-text-span">{{ user.is_verified ? 'Vérifié' : 'En attente' }}</span>
              </span>
            </td>
            <td class="status-cell-premium">
              <button class="btn-action-delete" (click)="onDeleteUser(user.id)">
                <i class="bi bi-trash3-fill"></i> Supprimer
              </button>
            </td>
          </tr>
        </tbody>
      </table>

    </div>
  </div>
</div>
